import React, { useState } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { updateProfile } from '../redux/slices/authSlice';
import authService from '../api/services/authService';
import { NODE_API } from '../api/config';
import { toast } from 'react-toastify';
import './EditProfile.css';

const EditProfile = () => {
  const { user } = useSelector((state) => state.auth);
  const dispatch = useDispatch();
  const navigate = useNavigate();

  const [form, setForm] = useState({
    fullName: user?.fullName || '',
    about: user?.about || '',
    phoneNumber: user?.phoneNumber || '',
    state: user?.state || '',
    city: user?.city || '',
    weight: user?.weight || '',
    height: user?.height || '',
    age: user?.age || '',
    gender: user?.gender || '',
    country: user?.country || '',
  });
  const [saving, setSaving] = useState(false);
  const [uploadingPic, setUploadingPic] = useState(false);
  const [uploadingBanner, setUploadingBanner] = useState(false);

  const getImageUrl = (path) => {
    if (!path) return null;
    if (path.startsWith('http')) return path;
    return `${NODE_API}/${path}`;
  };

  const handleChange = (field, value) => {
    setForm((prev) => ({ ...prev, [field]: value }));
  };

  const handleSave = async (e) => {
    e.preventDefault();
    if (!form.fullName.trim()) {
      toast.warn('Please enter your name');
      return;
    }
    setSaving(true);
    try {
      await authService.saveProfile({
        fullName: form.fullName.trim(),
        about: form.about,
        phoneNumber: form.phoneNumber,
        state: form.state,
        city: form.city,
        weight: form.weight,
        height: form.height,
        age: form.age,
        gender: form.gender,
        country: form.country,
      });
      dispatch(updateProfile(form));
      toast.success('Profile updated');
      navigate('/profile');
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to update profile');
    }
    setSaving(false);
  };

  const handleProfilePic = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setUploadingPic(true);
    try {
      const formData = new FormData();
      formData.append('image', file);
      const response = await authService.uploadProfilePic(formData);
      const imageURL = response.data?.data?.imageURL || response.data?.imageURL;
      if (imageURL) dispatch(updateProfile({ imageURL }));
      toast.success('Profile photo updated');
    } catch (error) {
      toast.error('Failed to upload photo');
    }
    setUploadingPic(false);
  };

  const handleBanner = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setUploadingBanner(true);
    try {
      const formData = new FormData();
      formData.append('image', file);
      const response = await authService.uploadBanner(formData);
      const bannerURL = response.data?.data?.bannerURL || response.data?.bannerURL;
      if (bannerURL) dispatch(updateProfile({ bannerURL }));
      toast.success('Banner updated');
    } catch (error) {
      toast.error('Failed to upload banner');
    }
    setUploadingBanner(false);
  };

  const avatarUrl = getImageUrl(user?.imageURL?.original || user?.imageURL?.thumbnail || user?.imageURL);
  const bannerUrl = getImageUrl(user?.bannerURL?.original || user?.bannerURL);

  return (
    <div className="edit-profile-page">
      <div className="edit-profile-header">
        <button className="edit-back-btn" onClick={() => navigate('/profile')}>←</button>
        <h1 className="edit-title">Edit Profile</h1>
        <div className="edit-header-spacer" />
      </div>

      {/* Banner upload */}
      <div className="edit-banner-section">
        <label className="edit-banner-label">
          <div
            className="edit-banner-preview"
            style={bannerUrl ? { backgroundImage: `url(${bannerUrl})` } : {}}
          >
            <span className="edit-banner-overlay">
              {uploadingBanner ? 'Uploading...' : '📷 Change Banner'}
            </span>
          </div>
          <input type="file" accept="image/*" onChange={handleBanner} hidden disabled={uploadingBanner} />
        </label>
      </div>

      {/* Avatar upload */}
      <div className="edit-avatar-section">
        <label className="edit-avatar-label">
          {avatarUrl ? (
            <img src={avatarUrl} alt="Profile" className="edit-avatar" />
          ) : (
            <div className="edit-avatar-placeholder">
              {(user?.fullName || 'U')[0].toUpperCase()}
            </div>
          )}
          <span className="edit-avatar-overlay">
            {uploadingPic ? '...' : '📷'}
          </span>
          <input type="file" accept="image/*" onChange={handleProfilePic} hidden disabled={uploadingPic} />
        </label>
      </div>

      {/* Form */}
      <form className="edit-form" onSubmit={handleSave}>
        <label className="edit-label">Full Name</label>
        <input className="edit-input" value={form.fullName} onChange={(e) => handleChange('fullName', e.target.value)} />

        <label className="edit-label">About</label>
        <textarea className="edit-textarea" value={form.about} onChange={(e) => handleChange('about', e.target.value)} rows={3} />

        <label className="edit-label">Phone Number</label>
        <input className="edit-input" value={form.phoneNumber} onChange={(e) => handleChange('phoneNumber', e.target.value)} />

        <div className="edit-row">
          <div className="edit-col">
            <label className="edit-label">City</label>
            <input className="edit-input" value={form.city} onChange={(e) => handleChange('city', e.target.value)} />
          </div>
          <div className="edit-col">
            <label className="edit-label">State</label>
            <input className="edit-input" value={form.state} onChange={(e) => handleChange('state', e.target.value)} />
          </div>
        </div>

        <label className="edit-label">Country</label>
        <input className="edit-input" value={form.country} onChange={(e) => handleChange('country', e.target.value)} />

        <div className="edit-row">
          <div className="edit-col">
            <label className="edit-label">Age</label>
            <select className="edit-input" value={form.age} onChange={(e) => handleChange('age', e.target.value)}>
              <option value="">Select</option>
              {Array.from({ length: 91 }, (_, i) => i + 10).map((a) => (
                <option key={a} value={a}>{a}</option>
              ))}
            </select>
          </div>
          <div className="edit-col">
            <label className="edit-label">Gender</label>
            <div className="edit-gender-row">
              {['Male', 'Female'].map((g) => (
                <label key={g} className="edit-radio-label">
                  <input
                    type="radio"
                    name="gender"
                    value={g}
                    checked={form.gender === g}
                    onChange={(e) => handleChange('gender', e.target.value)}
                  />
                  <span>{g}</span>
                </label>
              ))}
            </div>
          </div>
        </div>

        <div className="edit-row">
          <div className="edit-col">
            <label className="edit-label">Weight</label>
            <input className="edit-input" value={form.weight} onChange={(e) => handleChange('weight', e.target.value)} placeholder="lbs" />
          </div>
          <div className="edit-col">
            <label className="edit-label">Height</label>
            <input className="edit-input" value={form.height} onChange={(e) => handleChange('height', e.target.value)} placeholder="ft" />
          </div>
        </div>

        <button type="submit" className="edit-save-btn" disabled={saving}>
          {saving ? 'Saving...' : 'Save Changes'}
        </button>
      </form>
    </div>
  );
};

export default EditProfile;
